const Browser= (props)=>{
  
  let keys = _Util.getGlobalsKeys();
  let idWatch = "";
  let classN = "";

  const [initialize, setInitialize] = useState(false); 
  
  const observeChanges =  useSelector(selectObserveChanges);
  const wscre =  useSelector(selectObserveScreenWidth);
  const loginObs =  useSelector(selectLoginObs);
  

  if(!getDispatch()){
    const dispatch = useDispatch();
    UpdateRdx(dispatch)
  }

  useEffect(() => {
    if(!initialize){
      //initWebSocketClient();
      setInitialize(true);
      loadCmpTemp();
      _Util.initConfig().then(d=>{
        allUserSubscribe();
        setTimeout(()=>{
          _Util.getBrowser();         
          idWatch = keys[99];
          classN = _styleWatch(idWatch)
          _Util.updStore('imageBlob',false);          
          window.scrollTo(0,0);
          _Util.initCryptoJS();
          if(!_Util.genFP16bytes(true)){
            _Util.initFingerprint2();
          }
          // _Util.initGapi(()=>loadAuth());
          //verifyTk();
          getThumbnailImg("qvaMarket_logo2.png");
          loadFSd();
          // _Util.updStore("singinView",true)
        },350)
      })
    }
    if(props.history && !_Util.getStore()["route_history"]){
      _Util.updStore('route_history',props.history);
      updObserveChanges();
      if(props.location ){
        if(props.location.pathname ===  "/" || props.location.pathname ===  "/logout"){
          props.history.push({pathname:"/jessie_nails"})
          window.scrollTo(0,0)
        }
      }
    }
  });




  const loadFSd = async () => { 
    Subscribe()
   // let dd = await getCities()

  }
 // hrm-1128.appspot.com/o/jessie_nails
  /*********************************************************************************************************************************************/  
  /**********************     loadCmpTemp  initializing forms and store to start correctly the app      ****************************************/
  /*********************************************************************************************************************************************/
  

  const loadCmpTemp = () => { 
    let filtersMov = _Util.getStore()["filtersMov"] || {}
    if(!filtersMov["year"]){
      filtersMov["year"] = (new Date()).getFullYear();
    }
    if(!filtersMov["month"]){
      filtersMov["month"] = (new Date()).getMonth();
    }
    _Util.updStore("filtersMov",filtersMov)
    
  }
  


/*********************************************************************************************************************************************/  
/********************************************************     Render app      ****************************************************************/
/*********************************************************************************************************************************************/
  



if(props.location ){
  if(props.location.pathname ===  "/" || props.location.pathname ===  "/logout"){
    props.history.push({pathname:"/jessie_nails"});
    window.scrollTo(0,0)
  }
}

let isMobile = _Util.isMobile() ;


let appLoaded = true;

if(!_Util.getStore("singinView") && appLoaded){
    return (
      <>
      <div  id={keys[90]} is-mobile={`${isMobile}`} >
          <div className={!isMobile?'_app_body_content_ is_desktop':"is_mobile"}>  
            <div id={`data_ui_${keys[93]}`} style={{position:"static"}}>
              <HeaderJessie/>
              <div style={{ minHeight:"700px"}}>
              <Switch>
                  <Route path="/appointments" component={Calendd} />
                  <Route path="/jessie_nails" component={JessieNails} />
              </Switch>
              </div>
              <Footer/>
            </div>
          </div>   
          <style>{classN}</style>
        </div>
        <>
          <DialogModal/>
          <DialogHRM/>
          <SlideModalHRM />
          <Toast/>
        </>
        {_Util.getStore("showGSB")?<div id="g-s-b" data-theme="dark" hidden  ></div>:null}
        <ScrollRdx/>
      </>
    )
  }
  else if(_Util.getStore("singinView")){
    return (
        <Login />
    )
  }
  else{
    return (
      <>
      <div className={`_dsplFlx spaceAround loadingContainer`}>
        <LoadingColorSpinner stroke={'#e91e63'} height={120} width={120}/>
      </div>
      <div id="g-s-b" data-theme="dark" hidden  ></div>
      </>
    )
  }
  
} 


