  const verifyTk = async () => {

    if(!(_Util.getStore('userProfile') && _Util.getStore('userProfile').email)){
      
      let id_token = _Util.check_cookie_name("fs_us_id") || window.localStorage.getItem("fs_us_id");
      console.log(id_token)
      if(id_token){
        let dCt =  _Util.decryptV4(id_token,_Util.fs_cdata());
        console.log(dCt)
        let td = {}
        if(td && td.token){
          _Util.updStore('userProfile',td.user);
          _Util.updStore('isSpaOwner',td.user && td.user.isSpaOwner);
          updObserveChanges();
        }else{
          _Util.initGapi(()=>loadAuth());
          // getAnonymus();
        }
      }
      else{
        _Util.initGapi(()=>loadAuth());
      }
    }
  }







