import { createSlice } from '@reduxjs/toolkit'
import * as _Util from './Util'

const initialState = { 
  eventObs: 0, imageObs: 0, observeCmpt:0, 
  observeForms: 0, observeChanges:0, 
  observeScroll: 0, observeScreenWidth:0, 
  observeAppointment: 0,
  observe_calendar:0,
  observe_login: 0
}



const qvamarketsSlice = createSlice({
  name: 'qvamarkets',
  initialState,
  reducers: {
    setImageObs(state) {
      state.imageObs = _Util.gen12CodeId()
    },
    setEventObs(state) {
      state.eventObs = _Util.gen12CodeId()
    },
    setObserveCmpt(state) {
      state.observeCmpt = _Util.gen12CodeId()
    },    
    setObsForm(state) {
      state.observeForms = _Util.gen12CodeId()
    },
    setObserveChanges(state) {
      state.observeChanges = _Util.gen12CodeId()
    },
    setObserveScroll(state,action) {
      state.observeScroll = action.payload
    },
    setObserveScreenWidth(state,action) {
      state.observeScreenWidth = action.payload
    },
    setObserveAppointment(state,action) {
      state.observeAppointment = _Util.gen12CodeId()
    },
    setObserveCalendar(state,action) {
      state.observe_calendar = _Util.gen12CodeId()
    },
    setObserveLogin(state,action) {
      state.observe_login = _Util.gen12CodeId()
    }
  },
})


export const selectImageObs =  (state) => state.qvamarkets.imageObs;
export const selectEventObs =  (state) => state.qvamarkets.eventObs;
export const selectObserveCmpt =  (state) => state.qvamarkets.observeCmpt;
export const selectObserveForms =  (state) => state.qvamarkets.observeForms;
export const selectObserveChanges =  (state) => state.qvamarkets.observeChanges;
export const selectObserveScroll =  (state) => state.qvamarkets.observeScroll;
export const selectObserveScreenWidth =  (state) => state.qvamarkets.observeScreenWidth;
export const selectObserveAppointment =  (state) => state.qvamarkets.observeAppointment;

export const selectCalendarObs=  (state) => state.qvamarkets.observe_calendar;
export const selectLoginObs=  (state) => state.qvamarkets.observe_login;

export const { 
  setEventObs, setObserveChanges, setImageObs, 
  setObserveCmpt, setObsForm, setObserveScroll, 
  setObserveScreenWidth, setObserveAppointment,
  setObserveCalendar,
  setObserveLogin
} = qvamarketsSlice.actions
export default qvamarketsSlice